INSERT INTO sys_role_menu_two(role_id, menu_id)
SELECT id, #{menu_id}
FROM sys_role
WHERE del_flag = '0'
AND NOT EXISTS (
    SELECT 1 FROM sys_role_menu_two
    WHERE role_id = sys_role.id AND menu_id = #{menu_id}
)

